previewCss:
.darma-loader-darma-custom-545 {color: var(--loader-color, #0ea5e9);
  --loader-secondary-color: #67e8f9;
  --loader-bg: #ffffff;
   width:50px;
   aspect-ratio: 1;
   display: grid;
}
.darma-loader-darma-custom-545:before, .darma-loader-darma-custom-545:after  {
  content: "";
   grid-area: 1/1;
   --c:#0000 calc(100%/3),var(--loader-color, #0ea5e9) 0 calc(2*100%/3),#0000 0;
   --c1:linear-gradient(90deg,var(--c));
   --c2:linear-gradient( 0deg,var(--c));
   background: var(--c1),var(--c2),var(--c1),var(--c2);
   background-size: 300% 4px,4px 300%;
   background-repeat: no-repeat;
   animation: darma-loader-darma-custom-545-l11 1s infinite linear;
}
.darma-loader-darma-custom-545:after  {
  margin: 10px;
   transform: scaleX(-1);
   animation-delay: -.25s;
}
@keyframes darma-loader-darma-custom-545-l11  {
  0% {background-position: 50% 0,100% 100%,0 100%,0 0}
25% {background-position: 0 0,100% 50% ,0 100%,0 0}
50% {background-position: 0 0,100% 0 ,50% 100%,0 0}
75% {background-position: 0 0,100% 0 ,100% 100%,0 50%}
75.01%{background-position: 100% 0,100% 0 ,100% 100%,0 50%}
100% {background-position: 50% 0,100% 0 ,100% 100%,0 100%}
}

